echo "🔥 กำลังติดตั้ง CHAIYA V2RAY PRO MAX v7..."
export DEBIAN_FRONTEND=noninteractive
export NEEDRESTART_MODE=a
export NEEDRESTART_SUSPEND=1

# kill needrestart / dpkg locks ที่อาจค้างอยู่
systemctl stop unattended-upgrades 2>/dev/null || true
systemctl disable unattended-upgrades 2>/dev/null || true
pkill -f unattended-upgrades 2>/dev/null || true
pkill -f needrestart 2>/dev/null || true
rm -f /var/lib/dpkg/lock-frontend /var/lib/dpkg/lock /var/cache/apt/archives/lock 2>/dev/null || true
dpkg --configure -a 2>/dev/null || true

apt-get update -y -qq \
  -o Dpkg::Options::="--force-confdef" \
  -o Dpkg::Options::="--force-confold"

apt-get install -y -qq \
  -o Dpkg::Options::="--force-confdef" \
  -o Dpkg::Options::="--force-confold" \
  curl wget python3 bc qrencode ufw nginx certbot \
  python3-certbot-nginx python3-pip fail2ban sqlite3 2>/dev/null || true
systemctl stop apache2 2>/dev/null; systemctl disable apache2 2>/dev/null
systemctl stop xray 2>/dev/null; systemctl disable xray 2>/dev/null
rm -f /etc/systemd/system/xray.service /usr/local/bin/xray /usr/local/bin/chaiya-reload-users
rm -rf /usr/local/etc/xray /var/log/xray
systemctl daemon-reload 2>/dev/null
mkdir -p /etc/chaiya /var/www/chaiya/config
touch /etc/chaiya/vless.db /etc/chaiya/banned.db /etc/chaiya/iplog.db /etc/chaiya/datalimit.conf
ufw --force enable
ufw allow 22/tcp; ufw allow 80/tcp; ufw allow 443/tcp; ufw allow 8080/tcp; ufw allow 8880/tcp; ufw allow 2053/tcp
pip3 install py3xui --break-system-packages -q 2>/dev/null

printf "%s" "" | base64 -d > /etc/nginx/sites-available/chaiya
ln -sf /etc/nginx/sites-available/chaiya /etc/nginx/sites-enabled/chaiya
rm -f /etc/nginx/sites-enabled/default
nginx -t && systemctl enable nginx && systemctl restart nginx

echo "✅ ติดตั้ง chaiya-autoblock..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-autoblock
chmod +x /usr/local/bin/chaiya-autoblock
echo "✅ ติดตั้ง chaiya-bughost..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-bughost
chmod +x /usr/local/bin/chaiya-bughost
echo "✅ ติดตั้ง chaiya-cpukiller..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-cpukiller
chmod +x /usr/local/bin/chaiya-cpukiller
echo "✅ ติดตั้ง chaiya-delete-user..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-delete-user
chmod +x /usr/local/bin/chaiya-delete-user
echo "✅ ติดตั้ง chaiya-gen-page..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-gen-page
chmod +x /usr/local/bin/chaiya-gen-page
echo "✅ ติดตั้ง chaiya-main..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya
chmod +x /usr/local/bin/chaiya
echo "✅ ติดตั้ง chaiya-manage-user..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-manage-user
chmod +x /usr/local/bin/chaiya-manage-user
echo "✅ ติดตั้ง chaiya-online..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-online
chmod +x /usr/local/bin/chaiya-online
echo "✅ ติดตั้ง chaiya-reboot-menu..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-reboot-menu
chmod +x /usr/local/bin/chaiya-reboot-menu
echo "✅ ติดตั้ง chaiya-setup-xui..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-setup-xui
chmod +x /usr/local/bin/chaiya-setup-xui
echo "✅ ติดตั้ง chaiya-show-accounts..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-show-accounts
chmod +x /usr/local/bin/chaiya-show-accounts

# scan_and_enforce cron ถูกลบออก (function ไม่มีใน script)

echo ""
echo "======================================"
echo "✅ ติดตั้ง CHAIYA V2RAY PRO MAX v4 เสร็จแล้ว!"
echo "👉 พิมพ์: chaiya เพื่อเปิดเมนู"
echo "🔥 กดเมนู 1 เพื่อติดตั้ง 3x-ui ก่อนครับ"
echo "======================================"

# inbound สร้างอัตโนมัติโดย chaiya-setup-xui (เมนู 1) ซึ่งมี retry loop แล้ว
